/*!50003 CREATE*/ /*!50017 DEFINER=`root`@`localhost`*/ /*!50003 TRIGGER `trg_sys_system_file_insert` BEFORE INSERT ON `system_file` FOR EACH ROW -- 每一行数据都触发

BEGIN

    -- 如果插入时没传create_time，自动填充为当前时间戳

    IF NEW.create_time IS NULL THEN

        SET NEW.create_time = UNIX_TIMESTAMP();

    END IF;

    -- 插入时同时初始化update_time（和create_time保持一致）

    IF NEW.update_time IS NULL THEN

        SET NEW.update_time = UNIX_TIMESTAMP();

    END IF;

END */;;
DELIMITER ;
