/*!50003 CREATE*/ /*!50017 DEFINER=`root`@`localhost`*/ /*!50003 TRIGGER `trg_sys_user_role_before_update` BEFORE UPDATE ON `user_role` FOR EACH ROW BEGIN

    -- 更新时强制把update_time设为当前时间戳（无论是否传值）

    SET NEW.update_time = UNIX_TIMESTAMP();

END */;;
