DROP TABLE IF EXISTS `vehicle_license_archive`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `vehicle_license_archive` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `workorder_id` bigint DEFAULT NULL,
  `license_plate` varchar(50) DEFAULT NULL COMMENT '车牌号',
  `vehicle_type` varchar(100) DEFAULT NULL,
  `owner_name` varchar(100) DEFAULT NULL,
  `usage_nature` varchar(100) DEFAULT NULL COMMENT '使用性质',
  `brand_model` varchar(100) DEFAULT NULL COMMENT '品牌型号',
  `vehicle_code` varchar(100) DEFAULT NULL COMMENT '车架号',
  `engine_code` varchar(100) DEFAULT NULL COMMENT '发动机号',
  `registration_date` bigint DEFAULT NULL,
  `issue_date` bigint DEFAULT NULL,
  `seats` int DEFAULT NULL,
  `approved_load_capacity` int DEFAULT NULL,
  `curb_weight` int DEFAULT NULL,
  `is_transfer` varchar(20) DEFAULT NULL,
  `transfer_date` bigint DEFAULT NULL,
  `create_time` bigint DEFAULT NULL,
  `update_time` bigint DEFAULT NULL,
  `update_by` bigint DEFAULT NULL,
  `is_delete` tinyint NOT NULL DEFAULT '0',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='行驶证';
